mapper.select:
SELECT C.BGM_ID AS id, C.BGM_NAME AS title, C.ARTIST AS artist, C.LYRICS AS lyrics, D.FILE_PATH AS path FROM HOMPI A INNER JOIN USER_ITEM_INVENTORY B ON A.OWNER_USER_ID = B.USER_ID INNER JOIN BGM C ON B.ITEM_ID = C.BGM_ID INNER JOIN ATTACH_FILE_MANAGE D ON C.BGM_FILE_ATTACH_ID = D.ATTACH_FILE_ID WHERE 1=1 AND A.HOMPI_ID = #{hompiId} AND B.ITEM_TYPE = 'M' AND DATE_ADD(B.USE_START_DT, INTERVAL B.AVAIL_DAY DAY) > NOW()
AND B.USE_YN = #{useYn}
AND C.ARTIST LIKE CONCAT('%', #{search}, '%')
AND C.BGM_NAME LIKE CONCAT('%', #{search}, '%')
ORDER BY B.ORDER_ID
LIMIT #{offset}, #{limit}
